mapper.select:
SELECT id, user_id, ai_character_id, text, embedding, memory_type,
       importance, source_message_id, last_accessed_at, access_count, created_at
FROM long_term_memory
WHERE user_id = #{userId}
  AND ai_character_id = #{aiCharacterId}
  AND memory_type = #{memoryType}
ORDER BY importance DESC, created_at DESC
LIMIT #{limit}

SELECT id, user_id, ai_character_id, text, embedding, memory_type,
       importance, source_message_id, last_accessed_at, access_count, created_at
FROM long_term_memory
WHERE user_id = #{userId}
  AND ai_character_id = #{aiCharacterId}
  AND importance >= #{minImportance}
ORDER BY importance DESC, created_at DESC
LIMIT #{limit}

SELECT id, user_id, ai_character_id, text, embedding, memory_type,
       importance, source_message_id, last_accessed_at, access_count, created_at,
       1 - (embedding <=> #{queryEmbedding}::vector) AS similarity
FROM long_term_memory
WHERE user_id = #{userId}
  AND ai_character_id = #{aiCharacterId}
  AND (embedding <=> #{queryEmbedding}::vector) < 0.3
ORDER BY embedding <=> #{queryEmbedding}::vector
LIMIT #{topK}
